import numpy as np

def search(query, df, bm25, model, index, top_k=10):
    query_lower = query.lower()
    query_tokens = query_lower.split()

    # Semantic search
    query_vec = model.encode([query])
    dist, idx = index.search(query_vec.astype("float32"), top_k * 10)
    sem_ranks = {id: i for i, id in enumerate(idx[0])}

    # BM25 search
    bm25_scores = bm25.get_scores(query_tokens)
    bm25_idx = np.argsort(bm25_scores)[::-1][:top_k * 10]
    bm25_ranks = {id: i for i, id in enumerate(bm25_idx)}

    # Reciprocal Rank Fusion
    combined_scores = {}
    all_ids = set(sem_ranks.keys()) | set(bm25_ranks.keys())
    for id in all_ids:
        score = 0.0
        if id in sem_ranks: score += 1.0 / (sem_ranks[id] + 60)
        if id in bm25_ranks: score += 1.0 / (bm25_ranks[id] + 60)
        combined_scores[id] = score

    sorted_ids = sorted(combined_scores, key=combined_scores.get, reverse=True)[:top_k]
    return df.iloc[sorted_ids][["title", "overview"]].to_dict("records")

