def search(query, df, bm25, model, index, top_k=10):
    query_vec = model.encode([query])
    distances, top_idx = index.search(query_vec.astype("float32"), top_k * 10)

    indices = top_idx[0]
    results = df.iloc[indices].copy()

    query_genres = [g.strip().lower() for g in query.split() if g.lower() in ["action", "adventure", "animation", "comedy", "crime", "documentary", "drama", "family", "fantasy", "history", "horror", "music", "mystery", "romance", "science", "thriller", "war", "western"]]

    def calculate_genre_boost(row):
        if not query_genres:
            return 1.0
        row_genres = str(row['genres']).lower()
        matches = sum(1 for g in query_genres if g in row_genres)
        return 1.0 + (matches * 0.2)

    results['boost'] = results.apply(calculate_genre_boost, axis=1)
